const GRAMMAR_UNITS = [{"unit":"Unit 1","title":"Measurements: ask & report","rules":[{"name":"Questions de mesure","note":"Utilise How + adjective pour demander une dimension/valeur.","patterns":["How long…? / How wide…? / How high…? / How deep…? / How heavy…? / How far…?"],"examples":[{"en":"How long is the duct run from the AHU to the diffuser?","fr":"Quelle est la longueur du réseau de gaines de la CTA au diffuseur ?"},{"en":"How deep is the trench for the supply pipe?","fr":"Quelle est la profondeur de la tranchée pour la conduite d’alimentation ?"}]},{"name":"Approximation & tolérances","note":"about / roughly / approximately pour des valeurs non exactes; within ±… pour tolérances.","examples":[{"en":"The measured airflow is approximately 520 m³/h, within ±5% of the design value.","fr":"Le débit mesuré est d’environ 520 m³/h, dans une tolérance de ±5% par rapport à la valeur de projet."}]},{"name":"Unités & lecture","note":"Toujours donner l’unité (mm, m, kg, Pa, °C) et préciser si c’est une moyenne ou une valeur instantanée.","examples":[{"en":"Average supply air temperature: 19.8 °C (10-min mean).","fr":"Température moyenne de soufflage : 19,8 °C (moyenne sur 10 min)."}]}],"exercises":[{"type":"mcq","prompt":"Choose the best question to ask for the vertical dimension of a wall.","options":["How long is the wall?","How high is the wall?","How wide is the wall?"],"answer":"How high is the wall?","explain":"« high » = hauteur (vertical)."},{"type":"fill","prompt":"Fill the blank: The pipe is ______ 12 meters long (approximation).","answer":"about","alts":["approximately","roughly"],"explain":"about / approximately / roughly = environ."},{"type":"mcq","prompt":"Choose the best unit for pressure drop in a duct.","options":["Pa","kg","m³/h"],"answer":"Pa","explain":"La perte de charge est une pression (Pa)."},{"type":"fill","prompt":"Fill the blank: The measured value is ______ ±5% of the design value.","answer":"within","explain":"within ±… = dans la tolérance de…"},{"type":"mcq","prompt":"Which sentence is clearer for a report?","options":["It is hot.","Supply air temperature: 20.2 °C.","It feels warm."],"answer":"Supply air temperature: 20.2 °C.","explain":"En technique, on préfère une valeur mesurée + unité."}]},{"unit":"Unit 2","title":"Frequency, space & shape","rules":[{"name":"Adverbes de fréquence","note":"Placement typique : before main verb / after 'be'.","examples":[{"en":"We usually check filters every month.","fr":"On vérifie généralement les filtres chaque mois."},{"en":"The pump is often noisy at start-up.","fr":"La pompe est souvent bruyante au démarrage."}]},{"name":"Every / once / twice","note":"every day/week; once a month; twice a year.","examples":[{"en":"The sensors are calibrated once a year.","fr":"Les capteurs sont étalonnés une fois par an."}]},{"name":"Prépositions d’espace","note":"on (surface), in (volume/zone), at (point précis).","examples":[{"en":"The thermostat is on the wall in the corridor, at the entrance.","fr":"Le thermostat est sur le mur dans le couloir, à l’entrée."}]},{"name":"Formes & géométrie","note":"square, rectangular, circular; diameter / radius.","examples":[{"en":"Use a circular duct with a diameter of 250 mm.","fr":"Utilise une gaine circulaire de diamètre 250 mm."}]}],"exercises":[{"type":"mcq","prompt":"Pick the correct word order.","options":["We check usually the valves.","We usually check the valves.","We check the valves usually."],"answer":"We usually check the valves.","explain":"Adverbe de fréquence avant le verbe principal."},{"type":"fill","prompt":"Fill the blank: The fire damper is installed ___ the ceiling.","answer":"in","explain":"in the ceiling = dans le plafond (volume)."},{"type":"mcq","prompt":"Choose the best preposition: The label is ___ the equipment (surface).","options":["on","in","at"],"answer":"on","explain":"on = sur une surface."},{"type":"fill","prompt":"Fill the blank: We replace this cartridge filter _____ a year.","answer":"twice","explain":"twice a year = deux fois par an."},{"type":"mcq","prompt":"Which is a shape?","options":["diameter","square","length"],"answer":"square","explain":"square = forme; diameter/length = dimensions."}]},{"unit":"Unit 3","title":"Comparison & relations","rules":[{"name":"Comparatif","note":"adj-er than / more adj than ; less … than.","examples":[{"en":"This fan is quieter than the previous model.","fr":"Ce ventilateur est plus silencieux que le modèle précédent."}]},{"name":"Superlatif","note":"the + adj-est / the most …","examples":[{"en":"This is the most efficient operating mode.","fr":"C’est le mode de fonctionnement le plus efficace."}]},{"name":"As…as / not as…as","note":"égalité / inégalité.","examples":[{"en":"The insulation is not as thick as specified.","fr":"L’isolation n’est pas aussi épaisse que prévu."}]},{"name":"Relations","note":"increase/decrease with; depends on; leads to.","examples":[{"en":"Pressure drop increases with airflow rate.","fr":"La perte de charge augmente avec le débit d’air."}]}],"exercises":[{"type":"mcq","prompt":"Choose the correct comparative.","options":["more high","higher","the higher"],"answer":"higher","explain":"high → higher."},{"type":"fill","prompt":"Fill the blank: This unit is _____ efficient than the old one.","answer":"more","alts":["more"],"explain":"more efficient than…"},{"type":"mcq","prompt":"Complete: The noise level is not as high ___ before.","options":["as","than","like"],"answer":"as","explain":"not as…as."},{"type":"fill","prompt":"Fill the blank: Temperature rises ____ solar gains increase.","answer":"as","explain":"as = à mesure que."},{"type":"mcq","prompt":"Which expresses a cause → result?","options":["whereas","therefore","similarly"],"answer":"therefore","explain":"therefore = donc (résultat)."}]},{"unit":"Unit 4","title":"Modification: intensity & approximation","rules":[{"name":"Degré / intensité","note":"slightly, moderately, highly, extremely.","examples":[{"en":"The room is slightly under-ventilated during peak occupancy.","fr":"La pièce est légèrement sous-ventilée en période de forte occupation."}]},{"name":"Approximation","note":"roughly / approximately / about + number.","examples":[{"en":"The duct length is roughly 18 m (including bends).","fr":"La longueur de gaine est d’environ 18 m (coudes inclus)."}]},{"name":"Qualifiers","note":"almost, nearly, practically, virtually.","examples":[{"en":"The AHU is virtually silent at low speed.","fr":"La CTA est quasiment silencieuse à basse vitesse."}]}],"exercises":[{"type":"mcq","prompt":"Pick the best word: The temperature is ___ stable (very stable).","options":["highly","slightly","barely"],"answer":"highly","explain":"highly stable = très stable."},{"type":"fill","prompt":"Fill the blank: The measured value is ______ 1.2 kW.","answer":"approximately","alts":["about","roughly"],"explain":"about / roughly / approximately."},{"type":"mcq","prompt":"Choose the closest meaning to 'virtually'.","options":["almost","never","exactly"],"answer":"almost","explain":"virtually ≈ almost."},{"type":"fill","prompt":"Fill the blank: The flow rate is ______ unchanged compared to last week.","answer":"practically","alts":["almost","nearly","virtually"],"explain":"practically unchanged = quasiment inchangé."},{"type":"mcq","prompt":"Which sentence is correctly hedged (not 100% certain)?","options":["It is exactly 50 Pa.","It is about 50 Pa.","It is 50 Pa, no doubt."],"answer":"It is about 50 Pa.","explain":"about = approximation."}]},{"unit":"Unit 5","title":"Link words & logic","rules":[{"name":"Addition","note":"in addition, moreover, furthermore.","examples":[{"en":"In addition, we verified the BMS trend logs.","fr":"En plus, nous avons vérifié les courbes du GTB."}]},{"name":"Contrast","note":"however, whereas, although.","examples":[{"en":"The supply is stable; however, the return fluctuates.","fr":"Le soufflage est stable ; cependant, le retour fluctue."}]},{"name":"Cause → effect","note":"because / since / therefore / as a result.","examples":[{"en":"The valve is stuck; therefore, the coil cannot be balanced.","fr":"La vanne est bloquée ; donc, la batterie ne peut pas être équilibrée."}]},{"name":"Clarification","note":"i.e. (that is), e.g. (for example).","examples":[{"en":"Use calibrated instruments, i.e., devices with valid certificates.","fr":"Utilise des instruments étalonnés, c.-à-d. avec certificats valides."}]}],"exercises":[{"type":"mcq","prompt":"Choose the best connector: The sensor was faulty; ___ we replaced it.","options":["therefore","although","whereas"],"answer":"therefore","explain":"cause → action."},{"type":"fill","prompt":"Fill the blank: The system is efficient; ______, it is expensive.","answer":"however","alts":["nevertheless"],"explain":"however = contraste."},{"type":"mcq","prompt":"Pick the correct use of e.g.","options":["e.g. means 'that is'.","e.g. introduces an example.","e.g. introduces a conclusion."],"answer":"e.g. introduces an example.","explain":"e.g. = for example."},{"type":"fill","prompt":"Fill the blank: We logged temperatures every minute, _____ we could identify peaks.","answer":"so that","alts":["so"],"explain":"so that = afin que / pour."},{"type":"mcq","prompt":"Choose the best connector for opposition between two facts.","options":["whereas","therefore","moreover"],"answer":"whereas","explain":"whereas = tandis que."}]},{"unit":"Unit 6","title":"Statements, knowledge & reporting","rules":[{"name":"Reporting results","note":"We found that… / The data show that… / It was observed that…","examples":[{"en":"It was observed that the temperature overshoots during start-up.","fr":"On a observé que la température dépasse la consigne au démarrage."}]},{"name":"Present perfect vs past simple","note":"present perfect = lien avec le présent; past simple = action datée/finie.","examples":[{"en":"We have tested the pump (and it is ready).","fr":"Nous avons testé la pompe (et elle est prête)."},{"en":"We tested the pump yesterday at 14:00.","fr":"Nous avons testé la pompe hier à 14:00."}]},{"name":"Passive voice (tech reports)","note":"is/was + past participle : 'is installed', 'was measured'.","examples":[{"en":"The airflow was measured at each diffuser.","fr":"Le débit d’air a été mesuré à chaque diffuseur."}]}],"exercises":[{"type":"mcq","prompt":"Choose the best report-style sentence.","options":["We saw it was hot.","It was observed that the room temperature was high.","The room was like, super hot."],"answer":"It was observed that the room temperature was high.","explain":"Style rapport technique."},{"type":"fill","prompt":"Fill the blank: The values ____ recorded in the commissioning report. (passive)","answer":"were","explain":"were recorded = passif au passé."},{"type":"mcq","prompt":"Pick the correct tense: We ___ the unit yesterday.","options":["have started","started","start"],"answer":"started","explain":"yesterday → past simple."},{"type":"fill","prompt":"Fill the blank: We have ____ the sensors and they are now stable.","answer":"calibrated","explain":"present perfect: action faite avec résultat actuel."},{"type":"mcq","prompt":"Choose the best reporting verb: The data ___ that airflow is insufficient.","options":["show","shows","showing"],"answer":"show","explain":"data (plural) → show (souvent)."}]}];
